сделай так чтобы в левом поддереве хранился больший элемент, в правом меньший(так же баланс следует считать как left - right)

Чтобы изменить Ваше AVL дерево так, чтобы в левом поддереве хранились элементы больше родительского узла, а в правом поддереве — меньше, вам необходимо будет изменить как логику сравнения значений в узлах, так и расчет баланса для каждого узла, а также высоты.

Вот измененная версия вашего кода, которая учитывает эти характеристики:

```cpp
#include <iostream>
#include <algorithm>

struct Node {
    int data;
    int height;
    int8_t balance;
    Node* left;
    Node* right;
    Node* parent;
};

struct AVL {
    Node* top = nullptr;

    int height(Node* node) {
        if (node == nullptr)
            return 0;
        return node->height;
    }

    void UpdateHeightAndBalance(Node* node) {
        if (node == nullptr)
            return;

        node->height = 1 + std::max(height(node->left), height(node->right));
        // Updated the balance calculation as left - right
        node->balance = height(node->left) - height(node->right);
    }

    Node* newNode(int value, Node* parent) {
        Node* node = new Node();
        node->data = value;
        node->left = nullptr;
        node->right = nullptr;
        node->parent = parent;
        node->height = 1;
        // Initialize node balance
        node->balance = 0;
        return node;
    }

    // Left and Right Rotations remain the same; only balance update changes.
    // (...)

    Node* Insert(Node* node, int key, Node* parent) {
        if (node == nullptr) {
            return newNode(key, parent);
        }

        // Since we want the larger elements on the left, we change the comparison
        if (key > node->data) {
            node->left = Insert(node->left, key, node);
        } else if (key < node->data) {
            node->right = Insert(node->right, key, node);
        } else {
            return node; // Duplicate keys not allowed
        }

        UpdateHeightAndBalance(node);
        return BalanceTree(node);
    }

    // The Delete function also remains principally the same;
    // just ensure the minValueNode() fetches the node from the left, not the right subtree
    // (...)

    bool Exists(Node* node, int key) {
        if (node == nullptr) return false;

        if (node->data == key) {
            return true;
        }
        // Check right subtree for smaller values and left subtree for larger values.
        else if (node->data < key) {
            return Exists(node->right, key);
        } else {
            return Exists(node->left, key);
        }
    }

  // (...) // Omitting other methods that remain unchanged.
};

int main() {
    // Main function remains unchanged, as it does not depend on the specific AVL tree properties
    // (...)
}
```

В указанном коде я изменил способ сравнения элементов в функции `Insert` и условие в функции `Exists` в соответствии с тем, чтобы в левом поддереве хранились элементы больше своего родителя, а в правом поддереве — меньше. Также было изменено обновление баланса в функции `UpdateHeightAndBalance`, чтобы баланс рассчитывался как `height(left) - height(right)`.

Пожалуйста, обратите внимание, что код `Rotate` и `BalanceTree` остаются прежними, так как их логика не изменяется; изменяется только способ обновления баланса внутри них.

