The issue appears to be in the `Delete` function implementation. Upon closer inspection, in the `Delete` function, there is a deletion logic issue with the handling of the case when the node has two children. You correctly find the minimum node in the right subtree (as we have inverted the left and right logic), but the deletion of the duplicate node does not properly rebalance the tree.

Let's correct this by explicitly rebalancing the path up to the root after deleting the node:

```cpp
Node* Delete(Node* node, int key) {
  if (node == nullptr) return node;

  if (key > node->data) {
    node->right = Delete(node->right, key);
  } else if (key < node->data) {
    node->left = Delete(node->left, key);
  } else {
    if ((node->left == nullptr) || (node->right == nullptr)) {
      Node* temp = node->left ? node->left : node->right;
      Node* parent = node->parent;

      if (temp != nullptr) {
        temp->parent = parent;
      }

      if (parent) {
        if (parent->left == node) {
          parent->left = temp;
        } else {
          parent->right = temp;
        }
      } else {
        top = temp;
      }

      delete node;
      node = temp;
    } else {
      // Rightmost node in left subtree
      Node* temp = node->left;
      while (temp->right != nullptr)
          temp = temp->right;

      node->data = temp->data;
      node->left = Delete(node->left, temp->data); // Use correct key for updated node
    }
  }

  if (node == nullptr) return node; // If we have deleted the node, return nullptr

