#include <iostream>

struct Node {
  int data;
  int height;
  int8_t balance;
  Node* left;
  Node* right;
  Node* parent;
};

struct AVL {
  Node* top = nullptr;

int height(Node* node) {
    if (node == nullptr)
      return 0;
    return node->height;
  }

  void UpdateHeightAndBalance(Node* node) {
    if (node == nullptr)
      return;

    node->height = 1 + std::max(height(node->left), height(node->right));
    node->balance = height(node->left) - height(node->right);
  }

  Node* newNode(int value, Node* parent) {
    Node* node = new Node();
    node->data = value;
    node->left = nullptr;
    node->right = nullptr;
    node->parent = parent;
    node->height = 1;
    node->balance = 0;
    return node;
}

  Node* RightRotation(Node* y) {
  Node* x = y->left;
  Node* T2 = x->right;

  x->right = y;
  y->left = T2;

  x->parent = y->parent; 
  y->parent = x;        
  if (T2 != nullptr) {
      T2->parent = y;
  }

  if (x->parent != nullptr) {
      if (x->parent->left == y) {
          x->parent->left = x;
      } else {
          x->parent->right = x;
      }
  } else {
      top = x; 
  }

  // Обновляем высоты и балансировку
  UpdateHeightAndBalance(y);
  UpdateHeightAndBalance(x);

  return x;
}

Node* LeftRotation(Node* x) {
    Node* y = x->right; 
    Node* T2 = y->left; 

    y->left = x;
    x->right = T2; 

    y->parent = x->parent;
    x->parent = y;
    if (T2 != nullptr) {
        T2->parent = x;
    }

    if (y->parent != nullptr) {
        if (y->parent->left == x) {
            y->parent->left = y;
        } else {
            y->parent->right = y;
        }
    } else {
        top = y;
    }

    UpdateHeightAndBalance(x);
    UpdateHeightAndBalance(y);

    return y;
  }

Node* BalanceTree(Node* node) {
  if (node == nullptr) return node;

  UpdateHeightAndBalance(node);

  if (node->balance == 2 && node->left->balance != -1) {
      return RightRotation(node);
  } else if (node->balance == 2 && node->left->balance == -1) {
      node->left = LeftRotation(node->left);
      return RightRotation(node);
  } else if (node->balance == -2 && node->right->balance != 1) {
      return LeftRotation(node);
  } else if (node->balance == -2 && node->right->balance == 1) {
      node->right = RightRotation(node->right);
      return LeftRotation(node);
  }

  return node;
}

  Node* Insert(Node* node, int key, Node* parent) {
    if (node == nullptr) {
      return newNode(key, parent);
